@GraphQlTest  // loads all GraphQL controllers — add specific class if multiple
class StockQueryTest {
    @Autowired GraphQlTester tester;
    @MockBean StockService stockService;

    @Test
    void stockBySymbol_returnsPriceAndName() {
        when(stockService.findBySymbol("TCS"))
            .thenReturn(new Stock("TCS", new BigDecimal("3500"), "Tata Consultancy Services"));

        tester.documentName("stockBySymbol")      // loads from graphql-test/stockBySymbol.graphql
            .variable("symbol", "TCS")
            .execute()
            .path("stockBySymbol.symbol").entity(String.class).isEqualTo("TCS")
            .path("stockBySymbol.price").entity(BigDecimal.class).isEqualTo(new BigDecimal("3500"))
            .path("stockBySymbol.companyName").entity(String.class).isEqualTo("Tata Consultancy Services");
    }

    @Test
    void stockBySymbol_unknownSymbol_returnsError() {
        when(stockService.findBySymbol("INVALID")).thenReturn(null);

        tester.documentName("stockBySymbol")
            .variable("symbol", "INVALID")
            .execute()
            .errors().satisfy(errors -> {
                // Either null data or a GraphQL error
                // (depends on how controller handles null)
            });
    }

    // KEY CONCEPTS:
    // documentName("name"): loads src/test/resources/graphql-test/name.graphql
    // .variable(key, value): passes typed variable to query
    // .path("field.subfield"): traverses the response data
    // .entity(Type.class): cast and assert
    // .errors().verify(): assert NO errors occurred
    // .errors().satisfy(): inspect errors when expected

    public static void main(String[] a) {
        System.out.println("@GraphQlTest: tester.documentName().variable().execute().path().entity()");
    }
