@GraphQlTest
class CreatePaymentMutationTest {
    @Autowired GraphQlTester tester;
    @MockBean PaymentService paymentService;

    @Test
    void createPayment_returnsInitiatedPayment() {
        when(paymentService.createPayment(any(PaymentInput.class)))
            .thenReturn(new PaymentResult("PAY-001", "INITIATED", 50000L, "HDFC"));

        tester.documentName("createPayment")
            .variable("input", Map.of(
                "merchantId", "MRC-001",
                "amountPaise", 50000,
                "gateway", "HDFC"
            ))
            .execute()
            .errors().verify()  // assert NO GraphQL errors
            .path("createPayment.paymentId").entity(String.class)
                .matches(id -> id.startsWith("PAY-"))
            .path("createPayment.status").entity(String.class).isEqualTo("INITIATED")
            .path("createPayment.amountPaise").entity(Long.class).isEqualTo(50000L)
            .path("createPayment.gateway").entity(String.class).isEqualTo("HDFC");
    }

    @Test
    void createPayment_invalidGateway_returnsError() {
        when(paymentService.createPayment(any()))
            .thenThrow(new IllegalArgumentException("Invalid gateway: UNKNOWN"));

