                "amountPaise", 50000,
                "gateway", "UNKNOWN"
            ))
            .execute()
            .errors().satisfy(errors -> {
                assert !errors.isEmpty() : "Should have at least one error";
            });
    }

    public static void main(String[] a) {
        System.out.println("Mutation test: .variable('input', Map.of()).execute().errors().verify().path().entity()");
