@GraphQlTest
class GraphQlErrorTest {
    @Autowired GraphQlTester tester;
    @MockBean StockService stockService;

    @Test
    void stock_notFound_returnsNotFoundError() {
        when(stockService.findBySymbol("INVALID"))
            .thenThrow(new NotFoundException("Stock 'INVALID' not found in NSE"));

        tester.documentName("stockBySymbol")
            .variable("symbol", "INVALID")
            .execute()
            .errors()
            .satisfy(errors -> {
                assertThat(errors).hasSize(1);
                assertThat(errors.get(0).getMessage()).contains("INVALID");
                // ErrorType depends on how the exception is mapped:
                // @DataFetcherExceptionResolver maps exceptions to ErrorType
            });
    }

    @Test
    void payment_negativeAmount_returnsBadRequest() {
        // GraphQL schema validation catches this before reaching controller:
        // amountPaise: Int! (non-null) — but negative values need custom validation
        tester.document("mutation { createPayment(input: {amountPaise: -100, gateway: \"HDFC\", merchantId: \"M1\"}) { paymentId } }")
            .execute()
            .errors()
            .satisfy(errors -> {
                // Either schema validation or controller exception
                assertThat(errors).isNotEmpty();
            });
    }

    @Test
    void multipleErrors_canBeInspected() {
        // GraphQL supports partial success: some fields resolve, some error
        // Test document using inline query (not file):
        tester.document("{ stockBySymbol(symbol: \"\") { price } }")
            .execute()
            .errors()
            .satisfy(errors -> {
                // Empty symbol validation
                assertThat(errors).isNotNull();
            });
    }

    // GRAPHQL ERROR TYPES:
    // ErrorType.NOT_FOUND: requested resource doesn't exist
    // ErrorType.BAD_REQUEST: invalid input (validation failure)
    // ErrorType.UNAUTHORIZED: not authenticated
    // ErrorType.FORBIDDEN: authenticated but not authorized
    // ErrorType.INTERNAL_ERROR: unexpected server error

    public static void main(String[] a) {
        System.out.println("GraphQL errors: .errors().satisfy(list -> assertThat(list).hasSize(1))");
    }
}

