import org.springframework.graphql.test.tester.*;
import org.springframework.boot.test.autoconfigure.graphql.*;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;
import org.junit.jupiter.api.*;
import reactor.core.publisher.Flux;
import java.math.BigDecimal;
import java.time.Duration;
import java.util.List;

record PriceUpdate(String symbol, BigDecimal price, long timestamp) {}
interface PriceStreamService { Flux<PriceUpdate> stream(String symbol); }

@GraphQlTest
class SubscriptionTest {
    @Autowired GraphQlTester tester;
    @MockBean PriceStreamService priceService;

    @Test
    void livePriceSubscription_emitsUpdates() {
        when(priceService.stream("RELIANCE")).thenReturn(
            Flux.just(
                new PriceUpdate("RELIANCE", new BigDecimal("2800"), 1000L),
                new PriceUpdate("RELIANCE", new BigDecimal("2810"), 2000L),
                new PriceUpdate("RELIANCE", new BigDecimal("2820"), 3000L)
            ).delayElements(Duration.ofMillis(10)) // simulate streaming
        );

        // src/test/resources/graphql-test/livePriceSubscription.graphql:
        // subscription LivePrice($symbol: String!) {
        //   livePrice(symbol: $symbol) {
        //     symbol
        //     price
        //     timestamp
        //   }
        // }
        List<PriceUpdate> updates = tester
            .documentName("livePriceSubscription")
            .variable("symbol", "RELIANCE")
            .executeSubscription()              // starts the subscription
            .toFlux()                           // converts to Flux
            .take(3)                            // take first 3 events
            .mapNotNull(r -> r.toEntity(PriceUpdate.class)) // deserialize each event
            .collectList()
            .block(Duration.ofSeconds(5));      // collect with timeout

        assertThat(updates).hasSize(3);
        assertThat(updates.get(0).price()).isEqualByComparingTo(new BigDecimal("2800"));
        assertThat(updates.get(1).price()).isEqualByComparingTo(new BigDecimal("2810"));
        // Prices are increasing (ascending order):
        assertThat(updates.get(0).price()).isLessThan(updates.get(2).price());
    }

    @Test
    void subscription_empty_completesNormally() {
        when(priceService.stream("UNKNOWN")).thenReturn(Flux.empty());

        List<PriceUpdate> updates = tester
            .documentName("livePriceSubscription")
            .variable("symbol", "UNKNOWN")
            .executeSubscription()
            .toFlux()
            .take(3)
            .mapNotNull(r -> r.toEntity(PriceUpdate.class))
            .collectList()
            .block(Duration.ofSeconds(2));

        assertThat(updates).isEmpty();
    }

    public static void main(String[] a) {
        System.out.println("Subscription: .executeSubscription().toFlux().take(N).collectList().block()");
    }
}

