record Position(String symbol, int quantity) {}
record TradeHistory(String symbol, List<String> trades) {}
interface PortfolioService { List<Position> getPortfolio(String accountId); }
interface TradeRepository { Map<String, TradeHistory> findBySymbols(List<String> symbols); }

@GraphQlTest
class DataLoaderTest {
    @Autowired GraphQlTester tester;
    @MockBean PortfolioService portfolioService;
    @MockBean TradeRepository tradeRepository;

    @Test
    void portfolio_usesDataLoader_notNPlusOne() {
        // 3 positions in portfolio:
        when(portfolioService.getPortfolio("ZER-001")).thenReturn(List.of(
            new Position("RELIANCE", 100),
            new Position("TCS", 50),
            new Position("INFY", 75)
        ));

        // DataLoader should batch: one call with ALL symbols
        when(tradeRepository.findBySymbols(anyList())).thenReturn(Map.of(
            "RELIANCE", new TradeHistory("RELIANCE", List.of("BUY 100", "SELL 20")),
            "TCS",      new TradeHistory("TCS", List.of("BUY 50")),
            "INFY",     new TradeHistory("INFY", List.of("BUY 75"))
        ));

        tester.documentName("portfolioWithHistory") // queries portfolio + tradeHistory for each
            .variable("accountId", "ZER-001")
            .execute()
            .errors().verify()
            .path("portfolio").entityList(Position.class).hasSize(3);

        // KEY ASSERTION: tradeRepository called ONCE with all 3 symbols (DataLoader batching)
        // Without DataLoader: called 3 times (N+1 queries)
        verify(tradeRepository, atMost(1)).findBySymbols(argThat(symbols ->
            symbols.containsAll(List.of("RELIANCE", "TCS", "INFY"))));
    }

    @Test
    void dataLoader_batchFunction_aggregatesKeys() {
        // Unit test for the DataLoader batch function:
        // In production: @Bean DataLoaderRegistrar that registers the batch load function
        // Batch function signature: List<String> keys -> CompletableFuture<List<TradeHistory>>

        List<String> batchedKeys = List.of("RELIANCE", "TCS", "INFY");
        Map<String, TradeHistory> result = Map.of(
            "RELIANCE", new TradeHistory("RELIANCE", List.of("BUY 100")),
            "TCS", new TradeHistory("TCS", List.of("BUY 50")),
            "INFY", new TradeHistory("INFY", List.of("BUY 75"))
        );
        when(tradeRepository.findBySymbols(batchedKeys)).thenReturn(result);

        Map<String, TradeHistory> loaded = tradeRepository.findBySymbols(batchedKeys);
        assertThat(loaded).hasSize(3);
        assertThat(loaded.get("TCS").trades()).containsExactly("BUY 50");
    }

    public static void main(String[] a) {
        System.out.println("DataLoader test: verify(repo, atMost(1)).findBySymbols(allKeys)");
    }
}

