class GraphQlHttpIntegrationTest {

    @Autowired WebTestClient webTestClient; // Spring provides this
    @MockBean StockService stockService;    // still mock the service layer

    HttpGraphQlTester tester; // wraps WebTestClient with GraphQL awareness

    @BeforeEach
    void setup() {
        tester = HttpGraphQlTester.create(
            webTestClient
                .mutate()
                .baseUrl("/graphql")         // GraphQL endpoint path
                .defaultHeader("Authorization", "Bearer test-token-zerodha")
                .build()
        );
    }

    @Test
    void integration_queryWithAuthHeader() {
        when(stockService.findAll()).thenReturn(List.of(
            new Stock("RELIANCE", new BigDecimal("2800"), "Reliance Industries")
        ));

        // This sends a REAL HTTP POST to /graphql with the Authorization header:
        tester.documentName("allStocks")
            .execute()
            .errors().verify()
            .path("allStocks").entityList(Stock.class).hasSize(1);
