        tester.documentName("getPortfolio")
            .variable("accountId", "ZER-001")
            .execute()
            .errors().satisfy(errors -> {
                // Either UNAUTHORIZED or empty data (depends on security config)
                // The test validates that unauthorized access is rejected
                assertThat(errors).isNotNull();
            });
