    @Test
    @WithMockUser(username = "zerodha-user", roles = {"USER"})
    void portfolio_withAuth_returnsData() {
        when(portfolioService.getPortfolio("ZER-001")).thenReturn(
            new Portfolio("ZER-001", new BigDecimal("1_50_000")));

