import org.springframework.graphql.test.tester.*;
import org.springframework.boot.test.autoconfigure.graphql.*;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;
import java.util.*;
import java.util.stream.*;

@GraphQlTest
class GraphQlPerformanceTest {
    @Autowired GraphQlTester tester;
    @MockBean StockService stockSvc;
    @MockBean PortfolioService portfolioSvc;

    @Test
    void simpleQuery_executesUnder50ms() {
        when(stockSvc.findBySymbol("RELIANCE"))
            .thenReturn(new Stock("RELIANCE", new BigDecimal("2800"), "Reliance"));

        long start = System.currentTimeMillis();
        tester.documentName("stockBySymbol")
            .variable("symbol", "RELIANCE")
            .execute().errors().verify();
        long elapsed = System.currentTimeMillis() - start;

        // Simple query should be fast:
        assertThat(elapsed)
            .as("Simple stock query should execute in < 200ms (mocked service)")
            .isLessThan(200); // lenient: mocked, but still validates no blocking
    }

    @Test
    void n_plus_one_detection() {
        // Setup: 1 position vs 100 positions
        List<Position> onePosition = List.of(new Position("RELIANCE", 100));
        List<Position> hundredPositions = IntStream.rangeClosed(1, 100)
            .mapToObj(i -> new Position("STOCK" + i, i))
            .collect(Collectors.toList());

        when(portfolioSvc.getPortfolio("ACC-1")).thenReturn(onePosition);
        when(portfolioSvc.getPortfolio("ACC-100")).thenReturn(hundredPositions);

        // Time 1-position query:
        long t1 = measureQuery("ACC-1");
        // Time 100-position query:
        long t100 = measureQuery("ACC-100");

        // With DataLoader (no N+1): times should be similar (1 batch call)
        // Without DataLoader (N+1): t100 ≈ 100 × t1
        // For mocked tests: both should be fast (mocks are instant)
        assertThat(t1).isLessThan(500);
        assertThat(t100).isLessThan(500);

        // DataLoader assertion: repository called ONCE regardless of position count
        // (Verified separately in DataLoader tests)
    }

    private long measureQuery(String accountId) {
        when(portfolioSvc.getPortfolio(accountId)).thenReturn(List.of(new Position("R", 1)));
        long start = System.currentTimeMillis();
        tester.documentName("getPortfolio")
            .variable("accountId", accountId)
            .execute();
        return System.currentTimeMillis() - start;
    }

    public static void main(String[] a) {
        System.out.println("GraphQL perf: measure elapsed, assert < threshold; N+1 check: compare 1 vs 100");
    }
}

import org.springframework.graphql.test.tester.*;
