import static org.mockito.Mockito.*;
import org.junit.jupiter.api.*;
import reactor.core.publisher.Flux;
import java.math.BigDecimal;
import java.time.Duration;
import java.util.*;

@GraphQlTest
class M27T5SynthesisTest {
    @Autowired GraphQlTester tester;
    @MockBean StockService stockSvc;
    @MockBean OrderService orderSvc;
    @MockBean PriceStreamService priceSvc;

    @Test
    void query_stock() {
        when(stockSvc.findBySymbol("HDFC"))
            .thenReturn(new Stock("HDFC", new BigDecimal("1600"), "HDFC Bank"));
        tester.documentName("stockBySymbol")
            .variable("symbol","HDFC")
            .execute().errors().verify()
            .path("stockBySymbol.symbol").entity(String.class).isEqualTo("HDFC")
            .path("stockBySymbol.price").entity(BigDecimal.class)
                .isEqualByComparingTo(new BigDecimal("1600"));
    }

    @Test
    void mutation_createOrder() {
        when(orderSvc.createOrder(any()))
            .thenReturn(new OrderResult("ORD-SYNTH","PLACED","HDFC"));
        tester.documentName("createOrder")
            .variable("input",Map.of("symbol","HDFC","quantity",10,"type","BUY"))
            .execute().errors().verify()
            .path("createOrder.orderId").entity(String.class).isEqualTo("ORD-SYNTH")
            .path("createOrder.status").entity(String.class).isEqualTo("PLACED");
    }

    @Test
    void error_unknownStock() {
        when(stockSvc.findBySymbol("UNKNOWN"))
            .thenThrow(new RuntimeException("Stock not found"));
        tester.documentName("stockBySymbol")
            .variable("symbol","UNKNOWN")
            .execute()
            .errors().satisfy(errors->assertThat(errors).isNotEmpty());
    }

    @Test
    void subscription_priceUpdates() {
        when(priceSvc.stream("HDFC")).thenReturn(
            Flux.just(
                new PriceUpdate("HDFC",new BigDecimal("1600"),1000L),
                new PriceUpdate("HDFC",new BigDecimal("1605"),2000L)
            ).delayElements(Duration.ofMillis(5)));

        List<PriceUpdate> updates = tester
            .documentName("livePriceSubscription")
            .variable("symbol","HDFC")
            .executeSubscription().toFlux()
            .take(2)
            .mapNotNull(r->r.toEntity(PriceUpdate.class))
            .collectList().block(Duration.ofSeconds(3));

        assertThat(updates).hasSize(2);
        assertThat(updates.get(0).price()).isEqualByComparingTo(new BigDecimal("1600"));
    }
}
